mapper.select:
SELECT rfc.*, b.bed_no as bedNo, r.room_no as roomNo, f.floor_name as floorName, bu.building_name as buildingName, p.project_name as projectName FROM elder_room_fee_config rfc LEFT JOIN elder_bed b ON FIND_IN_SET( b.id, rfc.item_id ) LEFT JOIN elder_room r ON FIND_IN_SET( r.id, rfc.item_id ) LEFT JOIN elder_floor f ON FIND_IN_SET( f.id, rfc.item_id ) LEFT JOIN elder_building bu ON FIND_IN_SET( bu.id, rfc.item_id ) LEFT JOIN elder_project p on p.id = rfc.project_id WHERE rfc.del_flag = 0
AND rfc.project_id IN (
#{id}
)
AND rfc.project_id = #{data.projectId}
AND r.room_no LIKE concat(concat('%',#{data.roomNo}),'%')
order by rfc.create_time desc
